INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (325, 'One in a million: celebrating the customers shaping AI’s future', 'More than one million customers around the world now use OpenAI to empower their teams and unlock new opportunities. This post highlights how companies like PayPal, Virgin Atlantic, BBVA, Cisco, Moderna, and Canva are transforming the way work gets done with AI.', 'More than one million customers around the world now use OpenAI to empower their teams and unlock new opportunities. This post highlights how companies like PayPal, Virgin Atlantic, BBVA, Cisco, Moderna, and Canva are transforming the way work gets done with AI.', 14, 'OpenAI Blog', 'https://openai.com/index/one-in-a-million-customers', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-12-22 00:00:00.000000', '2026-03-16 06:51:03.534869', 'https://openai.com/index/one-in-a-million-customers', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (326, 'Continuously hardening ChatGPT Atlas against prompt injection', 'OpenAI is strengthening ChatGPT Atlas against prompt injection attacks using automated red teaming trained with reinforcement learning. This proactive discover-and-patch loop helps identify novel exploits early and harden the browser agent’s defenses as AI becomes more agentic.', 'OpenAI is strengthening ChatGPT Atlas against prompt injection attacks using automated red teaming trained with reinforcement learning. This proactive discover-and-patch loop helps identify novel exploits early and harden the browser agent’s defenses as AI becomes more agentic.', 14, 'OpenAI Blog', 'https://openai.com/index/hardening-atlas-against-prompt-injection', '', 'ai_tech', '["GPT", "Security", "AI", "OpenAI"]', '2025-12-22 00:00:00.000000', '2026-03-16 06:51:03.534880', 'https://openai.com/index/hardening-atlas-against-prompt-injection', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (327, 'Evaluating chain-of-thought monitorability', 'OpenAI introduces a new framework and evaluation suite for chain-of-thought monitorability, covering 13 evaluations across 24 environments. Our findings show that monitoring a model’s internal reasoning is far more effective than monitoring outputs alone, offering a promising path toward scalable control as AI systems grow more capable.', 'OpenAI introduces a new framework and evaluation suite for chain-of-thought monitorability, covering 13 evaluations across 24 environments. Our findings show that monitoring a model’s internal reasoning is far more effective than monitoring outputs alone, offering a promising path toward scalable control as AI systems grow more capable.', 14, 'OpenAI Blog', 'https://openai.com/index/evaluating-chain-of-thought-monitorability', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2025-12-18 12:00:00.000000', '2026-03-16 06:51:03.534890', 'https://openai.com/index/evaluating-chain-of-thought-monitorability', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (328, 'Deepening our collaboration with the U.S. Department of Energy', 'OpenAI and the U.S. Department of Energy have signed a memorandum of understanding to deepen collaboration on AI and advanced computing in support of scientific discovery. The agreement builds on ongoing work with national laboratories and helps establish a framework for applying AI to high-impact research across the DOE ecosystem.', 'OpenAI and the U.S. Department of Energy have signed a memorandum of understanding to deepen collaboration on AI and advanced computing in support of scientific discovery. The agreement builds on ongoing work with national laboratories and helps establish a framework for applying AI to high-impact research across the DOE ecosystem.', 14, 'OpenAI Blog', 'https://openai.com/index/us-department-of-energy-collaboration', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-12-18 11:00:00.000000', '2026-03-16 06:51:03.534900', 'https://openai.com/index/us-department-of-energy-collaboration', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (329, 'Updating our Model Spec with teen protections', 'OpenAI is updating its Model Spec with new Under-18 Principles that define how ChatGPT should support teens with safe, age-appropriate guidance grounded in developmental science. The update strengthens guardrails, clarifies expected model behavior in higher-risk situations, and builds on our broader work to improve teen safety across ChatGPT.', 'OpenAI is updating its Model Spec with new Under-18 Principles that define how ChatGPT should support teens with safe, age-appropriate guidance grounded in developmental science. The update strengthens guardrails, clarifies expected model behavior in higher-risk situations, and builds on our broader work to improve teen safety across ChatGPT.', 14, 'OpenAI Blog', 'https://openai.com/index/updating-model-spec-with-teen-protections', '', 'ai_tech', '["AI", "GPT", "Safety", "OpenAI"]', '2025-12-18 11:00:00.000000', '2026-03-16 06:51:03.534910', 'https://openai.com/index/updating-model-spec-with-teen-protections', 0.0, 0);
